# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import requests

# Define Kong Admin API endpoint
kong_admin_url = "http://localhost:8001"

# Function to create a service in Kong
def create_service(name, url):
    service_data = {
        "name": name,
        "url": url
    }
    response = requests.post(f"{kong_admin_url}/services", json=service_data)
    if response.status_code == 201:
        print(f"Service '{name}' created successfully.")
        return response.json()
    else:
        print(f"Failed to create service '{name}'. Status code: {response.status_code}")
        return None

# Function to create a route in Kong
def create_route(service_id, paths):
    route_data = {
        "paths": paths,
        "service": {"id": service_id}
    }
    response = requests.post(f"{kong_admin_url}/routes", json=route_data)
    if response.status_code == 201:
        print("Route created successfully.")
        return response.json()
    else:
        print(f"Failed to create route. Status code: {response.status_code}")
        return None

# Function to add upstream targets
def add_upstream_targets(upstream_name, targets):
    for target in targets:
        target_data = {
            "target": target
        }
        response = requests.post(f"{kong_admin_url}/upstreams/{upstream_name}/targets", json=target_data)
        if response.status_code == 201:
            print(f"Target '{target}' added to upstream '{upstream_name}' successfully.")
        else:
            print(f"Failed to add target '{target}' to upstream '{upstream_name}'. Status code: {response.status_code}")

# Example usage
if __name__ == "__main__":
    # Create a service
    service = create_service("example-service", "http://example.com")

    if service:
        # Create a route for the service
        route = create_route(service["id"], ["/example"])

        if route:
            # Add upstream targets (assuming an upstream with name 'example-upstream' already exists)
            add_upstream_targets("example-upstream", ["192.168.0.1:80", "192.168.0.2:80"])